import {} from "../icons/names";
export function getForgeLogo(forgeName, small = false) {
    if (forgeName === "gitlab") {
        if (small) {
            return "gitlab";
        }
        return "gitlab";
    }
    else if (forgeName === "github") {
        if (small) {
            return "github";
        }
        return "github";
    }
    return "question";
}
