<script lang="ts">
	import { t } from "$lib/i18n/index.svelte";
	import ReduxResult from "$components/shared/ReduxResult.svelte";
	import {
		semanticTypeToString,
		treeStatusToShortString,
		type RuleFilter,
		type StackTarget,
		type WorkspaceRule,
	} from "$lib/rules/rule";
	import { RULES_SERVICE } from "$lib/rules/rulesService.svelte";
	import { getStackName } from "$lib/stacks/stack";
	import { STACK_SERVICE } from "$lib/stacks/stackService.svelte";
	import { inject } from "@gitbutler/core/context";
	import {
		Button,
		FileStatusBadge,
		Icon,
		KebabButton,
		ContextMenuSection,
		ContextMenuItem,
		Modal,
		Tooltip,
		type IconName,
	} from "@gitbutler/ui";

	type Props = {
		projectId: string;
		rule: WorkspaceRule;
		editRule: () => void;
	};

	const { rule, projectId, editRule }: Props = $props();

	const stackService = inject(STACK_SERVICE);
	const rulesService = inject(RULES_SERVICE);

	const [deleteRule, deletingRule] = rulesService.deleteWorkspaceRule;

	let confirmationModal = $state<Modal>();

	async function handleDeleteRule() {
		await deleteRule({
			projectId,
			ruleId: rule.id,
		});
	}

	function getFilterConfig(filter: RuleFilter): {
		icon: IconName | null;
		label: string;
		tooltip: string;
	} {
		switch (filter.type) {
			case "pathMatchesRegex":
				return {
					icon: "folder",
					label: filter.subject,
					tooltip: `Path: ${filter.subject}`,
				};
			case "contentMatchesRegex":
				return {
					icon: "text-contain",
					label: filter.subject,
					tooltip: `Containing text: ${filter.subject}`,
				};
			case "fileChangeType":
				return {
					icon: null,
					label: treeStatusToShortString(filter.subject),
					tooltip: `File change type: ${treeStatusToShortString(filter.subject)}`,
				};
			case "semanticType":
				return {
					icon: "tag",
					label: semanticTypeToString(filter.subject.type),
					tooltip: `Semantic type: ${semanticTypeToString(filter.subject.type)}`,
				};
		}
	}

	type FilterConfig = ReturnType<typeof getFilterConfig>;
</script>

{#snippet stackPill(icon: IconName, label: string, tooltip: string, hasError?: boolean)}
	<Tooltip text={tooltip}>
		<div class="target-pill" class:error={hasError}>
			<Icon name={icon} color={hasError ? "var(--fill-danger-bg)" : "var(--text-2)"} />
			<span class="text-12 truncate">{label}</span>
		</div>
	</Tooltip>
{/snippet}

{#snippet stackTarget(target: StackTarget)}
	{#if target.type === "stackId"}
		{@const stackId = target.subject}
		{@const stack = stackService.stackById(projectId, stackId)}
		<ReduxResult {projectId} result={stack.result}>
			{#snippet children(stack)}
				{#if stack !== null}
					{@const stackName = getStackName(stack)}
					{@render stackPill("branch", stackName, stackName)}
				{:else}
					{@render stackPill("danger", "branch missing", "Associated stack not found", true)}
				{/if}
			{/snippet}
		</ReduxResult>
	{:else if target.type === "leftmost"}
		{@render stackPill("leftmost-lane", "Leftmost", "Leftmost lane")}
	{:else if target.type === "rightmost"}
		{@render stackPill("rightmost-lane", "Rightmost", "Rightmost stack")}
	{/if}
{/snippet}

{#snippet renderBasicPill(config: FilterConfig)}
	<div class="filter-pill">
		<Tooltip text={config.tooltip}>
			<div class="flex items-center gap-6 overflow-hidden">
				{#if config.icon}
					<Icon name={config.icon} color="var(--text-2)" />
				{/if}
				<span class="text-12 truncate">{config.label}</span>
			</div>
		</Tooltip>
	</div>
{/snippet}

{#snippet renderFileChangePill(config: FilterConfig, fileStatus: any)}
	<Tooltip text={config.tooltip}>
		<div class="filter-pill">
			<FileStatusBadge status={fileStatus} style="dot" />
			<span class="text-12 truncate">{config.label}</span>
		</div>
	</Tooltip>
{/snippet}

{#snippet filterPill(filter: RuleFilter)}
	{@const config = getFilterConfig(filter)}

	{#if filter.type === "fileChangeType"}
		{@render renderFileChangePill(config, filter.subject)}
	{:else}
		{@render renderBasicPill(config)}
	{/if}
{/snippet}

{#snippet ruleActions()}
	<div class="rule__actions">
		<KebabButton minimal buttonClassname="extra-padding">
			{#snippet contextMenu({ close })}
				<ContextMenuSection>
					<ContextMenuItem
						label={t('rules.editRule')}
						icon="edit"
						onclick={() => {
							close();
							editRule();
						}}
					/>
					<ContextMenuItem
						label={t('rules.deleteRule')}
						icon="bin"
						onclick={async () => {
							close();
							confirmationModal?.show();
						}}
					/>
				</ContextMenuSection>
			{/snippet}
		</KebabButton>
	</div>
{/snippet}

{#if rule.action.type === "explicit" && rule.action.subject.type === "assign" && rule.trigger === "fileSytemChange"}
	{@const target = rule.action.subject.subject.target}
	{@const filters = rule.filters}

	<div class="rule" role="presentation" ondblclick={editRule}>
		<div class="flex items-center gap-4 flex-1 overflow-hidden m-r-4">
			{#if filters.length > 0}
				{#each filters as filter (filter.type)}
					{@render filterPill(filter)}
				{/each}
			{:else}
				<div class="filter-pill">
					<span class="text-12 truncate">{t('rules.allChanges')}</span>
				</div>
			{/if}
			<Tooltip text={t('rules.stageToBranch')}>
				<Icon name="arrow-right" color="var(--text-3)" />
			</Tooltip>
			{@render stackTarget(target)}
		</div>

		{@render ruleActions()}
	</div>
{/if}

<Modal
	bind:this={confirmationModal}
	width="small"
	type="warning"
	title={t('rules.deleteRule')}
	onSubmit={async (close) => {
		await handleDeleteRule();
		close();
	}}
>
	{t('rules.deleteConfirm')}

	{#snippet controls(close)}
		<Button kind="outline" onclick={close}>{t('common.cancel')}</Button>
		<Button loading={deletingRule.current.isLoading} style="danger" type="submit"
			>{t('rules.deleteRule')}</Button
		>
	{/snippet}
</Modal>

<style lang="postcss">
	.rule {
		display: flex;
		position: relative;
		align-items: center;
		padding: 10px;
		overflow: hidden;
		gap: 4px;
		border-bottom: 1px solid var(--border-3);

		&:last-child {
			border-bottom: none;
		}
	}

	.rule__actions {
		display: flex;
		align-items: center;
	}

	:global(.rule__actions .extra-padding) {
		padding: 4px;
	}

	.filter-pill,
	.target-pill {
		display: flex;
		align-items: center;
		height: 24px;
		padding: 0 6px;
		overflow: hidden;
		gap: 6px;
		border-radius: 100px;
	}

	.filter-pill {
		background-color: var(--bg-2);
	}

	.target-pill {
		background-color: var(--bg-2);
	}
</style>
